openscad:
case_diameter = 40; // [20:1:60]
case_thickness = 9; // [5:1:15]
dial_diameter = 36; // [15:1:55]
dial_thickness = 2; // [1:0.5:5]
hand_length = 14; // [5:1:25]
hand_width = 2; // [1:0.5:4]
lug_width = 20; // [10:1:30]
lug_length = 12; // [5:1:20]
$fn = 60;

module watch() {
    // Black case
    color("black")
    difference() {
        cylinder(d=case_diameter, h=case_thickness);
        translate([0,0,case_thickness-1])
            cylinder(d=case_diameter-3, h=3);
    }

    // White dial
    color("white")
    translate([0,0,case_thickness-dial_thickness])
        cylinder(d=dial_diameter, h=dial_thickness+0.1);

    // Hour hand
    color("black")
    translate([0,0,case_thickness-dial_thickness+0.5])
        rotate([0,0,30])
            cube([hand_width,hand_length,1.5], center=true);

    // Minute hand
    color("black")
    translate([0,0,case_thickness-dial_thickness+0.5])
        rotate([0,0,150])
            cube([hand_width*0.7,hand_length*1.2,1.5], center=true);

    // Crown
    color("black")
    translate([case_diameter/2-1,0,case_thickness/2])
        rotate([0,90,0])
            cylinder(d=5, h=4);

    // Lugs
    color("black") {
        translate([-case_diameter/2-lug_length/2,0,case_thickness/2])
            cube([lug_length,lug_width,case_thickness], center=true);
        translate([case_diameter/2+lug_length/2,0,case_thickness/2])
            cube([lug_length,lug_width,case_thickness], center=true);
    }
}

watch();
